import React, { useState, useEffect } from 'react';
import { io } from 'socket.io-client';
import './App.css';

const socket = io('http://localhost:5000');

function App() {
  const [step, setStep] = useState('profile'); // profile, chat
  const [gpa, setGpa] = useState('');
  const [interests, setInterests] = useState('');
  const [messages, setMessages] = useState([]);
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (step === 'chat') {
      socket.on('receive_message', (msg) => {
        setMessages(prev => [...prev, msg]);
      });
    }

    return () => {
      socket.off('receive_message');
    };
  }, [step]);

  const submitProfile = async () => {
    if (!gpa || !interests) {
      alert('Please fill both fields!');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/api/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          username: 'Lahar D',
          email: 'lahar@test.com',
          password: 'pass123',
          gpa: parseFloat(gpa),
          interests: interests
        })
      });

      const data = await response.json();
      
      if (response.ok) {
        alert('✅ Profile saved to MongoDB!');
        setStep('chat');
        setMessages([{ username: 'AI Counselor', message: 'Welcome Lahar! Ask me about colleges based on your GPA ' + gpa + ' and interests: ' + interests, isAI: true }]);
      } else {
        alert('Error: ' + data.error);
      }
    } catch (error) {
      alert('Backend connection failed. Check Terminal 1.');
    }
    setLoading(false);
  };

  const sendMessage = () => {
    if (!message.trim()) return;
    
    const userMessage = { username: 'Lahar', message, isAI: false };
    setMessages(prev => [...prev, userMessage]);
    socket.emit('send_message', { message, gpa, interests });
    setMessage('');
  };

  if (step === 'profile') {
    return (
      <div className="profile-container">
        <div className="profile-form">
          <h1>🎓 AI College Counselor</h1>
          <p>Enter your profile to get personalized recommendations</p>
          
          <input
            type="number"
            step="0.1"
            placeholder="GPA (e.g. 3.5)"
            value={gpa}
            onChange={(e) => setGpa(e.target.value)}
            className="input-field"
          />
          
          <input
            placeholder="Interests (CS, AI, Mechanical)"
            value={interests}
            onChange={(e) => setInterests(e.target.value)}
            className="input-field"
          />
          
          <button 
            onClick={submitProfile} 
            disabled={loading}
            className="submit-btn"
          >
            {loading ? 'Saving...' : '🚀 Start Counseling'}
          </button>
          
          <div className="status">
            Backend: <span className="green">localhost:5000 ✅</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>AI College Counselor</h2>
        <p>Your GPA: {gpa} | Interests: {interests}</p>
      </div>
      
      <div className="messages">
        {messages.map((msg, index) => (
          <div key={index} className={`message ${msg.isAI ? 'ai-message' : 'user-message'}`}>
            <strong>{msg.username}:</strong> {msg.message}
          </div>
        ))}
      </div>
      
      <div className="chat-input">
        <input
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
          placeholder="Ask about colleges, fees, admissions..."
          className="message-input"
        />
        <button onClick={sendMessage} className="send-btn">Send</button>
      </div>
    </div>
  );
}

export default App;
